if (! function_exists('text_autocorrect')) {
    function text_autocorrect($word, $dictionary, $max_distance = null, $max_results = null, $case_sensitive = null)
    {
        $word = trim($word);
        if (empty($word) || !is_array($dictionary) || empty($dictionary)) {
            return json_encode(['error' => 'Word and non-empty dictionary are required', 'corrections' => []]);
        }
        $maxDist = isset($max_distance) ? min(5, max(1, (int)$max_distance)) : 3;
        $maxResults = isset($max_results) ? max(1, (int)$max_results) : 5;
        $caseSensitive = isset($case_sensitive) ? (bool)$case_sensitive : false;

        $wordCompare = $caseSensitive ? $word : mb_strtolower($word);

        $scores = [];
        foreach ($dictionary as $entry) {
            $candidate = trim((string)$entry);
            if ($candidate === '' || ($caseSensitive ? $candidate : mb_strtolower($candidate)) === $wordCompare) {
                continue;
            }
            $candCompare = $caseSensitive ? $candidate : mb_strtolower($candidate);
            $dist = levenshtein($wordCompare, $candCompare);

            if ($dist <= $maxDist) {
                // Calculate similarity as a percentage
                $maxLen = max(strlen($wordCompare), strlen($candCompare));
                $similarity = $maxLen > 0 ? (1 - $dist / $maxLen) * 100 : 0;

                // Bonus for same first letter
                $firstLetterBonus = 0;
                if (strlen($wordCompare) > 0 && strlen($candCompare) > 0) {
                    if ($wordCompare[0] === $candCompare[0]) {
                        $firstLetterBonus = 5;
                    }
                }

                // Bonus for same length
                $lengthBonus = strlen($wordCompare) === strlen($candCompare) ? 3 : 0;

                $totalScore = $similarity + $firstLetterBonus + $lengthBonus;

                $scores[] = [
                    'suggestion' => $candidate,
                    'distance' => $dist,
                    'similarity_percent' => round($similarity, 1),
                    'score' => round($totalScore, 1),
                ];
            }
        }

        // Sort by distance ascending, then similarity descending
        usort($scores, function($a, $b) {
            if ($a['distance'] !== $b['distance']) return $a['distance'] - $b['distance'];
            return $b['similarity_percent'] - $a['similarity_percent'];
        });

        $results = array_slice($scores, 0, $maxResults);

        // If the word itself is in the dictionary, note it
        $exactMatch = false;
        $wordLower = $caseSensitive ? $word : mb_strtolower($word);
        foreach ($dictionary as $entry) {
            $entryCompare = $caseSensitive ? trim($entry) : mb_strtolower(trim($entry));
            if ($entryCompare === $wordLower) {
                $exactMatch = true;
                break;
            }
        }

        $bestSuggestion = !empty($results) ? $results[0]['suggestion'] : null;
        $nextSteps = [];
        if ($bestSuggestion && !$exactMatch) {
            $nextSteps[] = "Feed '$bestSuggestion' to text_autocomplete for prefix extensions.";
        }

        return json_encode([
            'input_word' => $word,
            'exact_match_in_dictionary' => $exactMatch,
            'dictionary_size' => count($dictionary),
            'corrections_found' => count($results),
            'corrections' => $results,
            'best_correction' => $bestSuggestion,
            'next_steps' => $nextSteps,
        ]);
    }
